// V-Groove Pulley — BREP / replicad
// A flat disk pulley with a V-shaped drive-belt groove around the rim,
// a center bore, a keyway slot, and chamfered side rims.
//
// Coordinates: axis along Z, sits flat on the XY plane.

const { BREP } = api;

// --- Tunables ---
const R_OUTER     = 25;    // outer disk radius (50 mm dia)
const H           = 15;    // disk thickness
const R_GROOVE    = 21;    // depth-of-groove minimum radius (≈4 mm deep into the rim)
const R_BORE      = 4;     // 8 mm dia center bore
const KEYWAY_W    = 2;     // square keyway cross-section
const RIM_CHAMFER = 1;     // outer rim top/bottom chamfer

// --- 1. Body: flat disk, then chamfer the two outer rim edges.
//     Fillet/chamfer BEFORE the boolean cuts (per replicad.md guidance:
//     OCCT's solver is sensitive to post-cut edge graphs).
//     Use parallelToPlane:'XY' to grab only the two horizontal rim circles
//     (not the vertical seam edge OCCT puts down the cylinder side).
const body = BREP.cylinder(R_OUTER, H)
  .chamfer(RIM_CHAMFER, { parallelToPlane: 'XY' });

// --- 2. V-groove cutter: a short thick cylinder, chamfered hard on top
//     and bottom so its cross-section is a bicone (triangle) pointing
//     radially outward. Subtracting it from the disk carves a V-groove
//     ring around the equator.
//
//     Cutter cylinder: radius R_OUTER + 3 (so it extends OUTSIDE the
//     disk and cleanly slices through the rim), height = 2 × groove depth.
//     The chamfer distance equals the cylinder's half-height, so the
//     top and bottom flat faces shrink to small "stubs" instead of
//     points — keeps OCCT's chamfer solver happy.
const grooveDepth  = R_OUTER - R_GROOVE;          // 4 mm radial depth
const cutterR      = R_OUTER + 3;                 // 28 mm; pokes past the rim
const cutterH      = 2 * grooveDepth + 1;         // 9 mm tall
const cutterChamfer = grooveDepth;                // 4 mm — gives a ~45° V

const grooveCutter = BREP.cylinder(cutterR, cutterH)
  .chamfer(cutterChamfer, { parallelToPlane: 'XY' })  // bevel both horizontal rim circles
  .translate([0, 0, (H - cutterH) / 2]);              // centre vertically on the disk

// --- 3. Center bore (8 mm dia through-hole). Run it slightly proud on
//     both ends so the cut surface is clean.
const bore = BREP.cylinder(R_BORE, H + 2).translate([0, 0, -1]);

// --- 4. Small keyway slot alongside the bore — a 2×2 square channel
//     in the +Y direction. Total Y-extent reaches just past R_BORE so
//     it merges with the bore wall.
const keyway = BREP.box([KEYWAY_W, KEYWAY_W, H + 2])
  .translate([0, R_BORE + KEYWAY_W / 2 - 0.4, -1]);

// --- 5. Combine everything: body minus (groove ring + bore + keyway).
return BREP.cutAll([body, grooveCutter, bore, keyway]);
